import { NodeAPI, Node, NodeDef, NodeMessage } from 'node-red';

/**
 * Ghi chú: kiểu `Node.on('input', ...)` trong gói @types/node-red không ổn định
 * giữa các phiên bản (phụ thuộc @node-red/registry đôi khi thiếu .d.ts và làm
 * overload resolution bị lệch). Để tránh phụ thuộc vào tiểu tiết đó, ta khai
 * báo kiểu tường minh cho callback rồi ép kiểu khi đăng ký listener, thay vì
 * dựa vào overload suy luận tự động của thư viện.
 */
type DongtienInputListener = (
    msg: NodeMessage & { payload: unknown; db?: string; precision?: string },
    send: (msg: NodeMessage) => void,
    done: (err?: Error | null) => void,
) => void;

/**
 * dongtien-insert
 * ----------------
 * Node dùng chung cho các loại đồng hồ đo điện (iLEC MFM300, Arcel ACM 96L E4,
 * CHINT PD7777, hoặc tuỳ chỉnh khác). Thay vì viết cứng metrics_definition và
 * device_info trong từng file function-node riêng lẻ (ilec_mfm300.ts,
 * arcel_acm.ts, chint_pd7777.ts), toàn bộ mapping "biến -> tên/đơn vị/độ chia"
 * và thông tin thiết bị (factory/transformer/parent_system/sub_system/device)
 * được cấu hình trực tiếp trên UI của node (xem node.html).
 *
 * Input  : msg.payload = { [machine_key]: [{ ts, values: { Ua: 220000, ... } }] }
 * Output : msg.payload = chuỗi Line Protocol (nhiều dòng, mỗi dòng 1 field "value")
 *          msg.db, msg.precision để node influxdb-batch / dongtien insert phía sau dùng.
 */

export interface MetricDefinition {
    /** Tên biến kỹ thuật trong raw_data, vd: "Ua", "Ib", "Pt" */
    key: string;
    /** Tên hiển thị / mô tả, vd: "Phase A Voltage" -> đưa vào tag "name" */
    name: string;
    /** Đơn vị đo, vd: "V", "A", "kW" -> đưa vào tag "unit" */
    unit: string;
    /** Độ chia (chia raw value để ra giá trị chuẩn), vd: 1000, 100, 10 */
    div: number;
}

export interface DongtienInsertNodeDef extends NodeDef {
    deviceType: string;
    factory: string;
    transformer: string;
    parentSystem: string;
    subSystem: string;
    device: string;
    measurement: string;
    db: string;
    precision: string;
    shiftVar: string;
    metrics: MetricDefinition[];
}

interface DongtienInsertNode extends Node {
    deviceType: string;
    factory: string;
    transformer: string;
    parentSystem: string;
    subSystem: string;
    device: string;
    measurement: string;
    db: string;
    precision: string;
    shiftVar: string;
    metricsMap: Record<string, MetricDefinition>;
}

/**
 * Escape ký tự đặc biệt cho InfluxDB Line Protocol (giữ đúng logic gốc trong
 * ilec_mfm300.ts / arcel_acm.ts / chint_pd7777.ts).
 */
function escapeString(value: unknown): string {
    if (value === undefined || value === null || value === '') return 'Unknown';
    return String(value)
        .replace(/\s/g, '\\ ')
        .replace(/,/g, '\\,')
        .replace(/=/g, '\\=');
}

module.exports = function (RED: NodeAPI) {
    function DongtienInsertNode(
        this: DongtienInsertNode,
        config: DongtienInsertNodeDef,
    ) {
        RED.nodes.createNode(this, config);
        const node = this;

        node.deviceType = config.deviceType || 'custom';
        node.factory = config.factory || '';
        node.transformer = config.transformer || '';
        node.parentSystem = config.parentSystem || '';
        node.subSystem = config.subSystem || '';
        node.device = config.device || '';
        node.measurement = config.measurement || 'electric_measurement';
        node.db = config.db || 'dongtien';
        node.precision = config.precision || 'ns';
        node.shiftVar = config.shiftVar || 'shift';

        // Chuẩn hoá danh sách metrics đã cấu hình trên UI thành map để tra cứu O(1)
        const rawMetrics: MetricDefinition[] = Array.isArray(config.metrics)
            ? config.metrics
            : [];

        node.metricsMap = {};
        for (const m of rawMetrics) {
            if (!m || !m.key) continue;
            const div = Number(m.div);
            node.metricsMap[m.key] = {
                key: m.key,
                name: m.name && m.name.trim() ? m.name : m.key,
                unit: m.unit || '',
                div: Number.isFinite(div) && div !== 0 ? div : 1,
            };
        }

        if (Object.keys(node.metricsMap).length === 0) {
            node.warn(
                'Chưa cấu hình biến nào (metrics rỗng). Node sẽ không xuất ra dữ liệu nào.',
            );
        }

        const onInput: DongtienInputListener = function (msg, send, done) {
            send = send || ((m: NodeMessage) => node.send(m));
            done =
                done ||
                ((err?: Error | null) => {
                    if (err) node.error(err, msg);
                });

            try {
                const shift =
                    (node.context().global.get(node.shiftVar) as string) ||
                    'Unassigned';

                const rawPayload = msg.payload as
                    | Record<string, Array<{ ts?: number; values?: Record<string, unknown> }>>
                    | undefined;

                if (!rawPayload || typeof rawPayload !== 'object') {
                    node.status({ fill: 'yellow', shape: 'ring', text: 'payload không hợp lệ' });
                    return done();
                }

                const machineKey = Object.keys(rawPayload)[0];
                const dataNode = machineKey ? rawPayload[machineKey]?.[0] : undefined;

                if (!machineKey || !dataNode) {
                    node.status({ fill: 'yellow', shape: 'ring', text: 'không có machine_key' });
                    return done();
                }

                // Giữ nguyên logic gốc: ts (giây hoặc ms tuỳ nguồn) * 1e6 -> ns
                const timestamp = (dataNode.ts || Date.now()) * 1000000;
                const rawData = dataNode.values || {};

                const lines: string[] = [];

                for (const key of Object.keys(rawData)) {
                    const metric = node.metricsMap[key];
                    if (!metric) continue;

                    const fieldValue = Number(rawData[key]) / metric.div;
                    if (Number.isNaN(fieldValue)) continue;

                    const tags = [
                        `factory=${escapeString(node.factory)}`,
                        `transformer=${escapeString(node.transformer)}`,
                        `parent_system=${escapeString(node.parentSystem)}`,
                        `sub_system=${escapeString(node.subSystem)}`,
                        `machine=${escapeString(machineKey)}`,
                        `device=${escapeString(node.device)}`,
                        `name=${escapeString(metric.name)}`,
                        `unit=${escapeString(metric.unit)}`,
                        `shift=${escapeString(shift)}`,
                    ];

                    lines.push(
                        `${node.measurement},${tags.join(',')} value=${fieldValue} ${timestamp}`,
                    );
                }

                if (lines.length === 0) {
                    node.status({
                        fill: 'yellow',
                        shape: 'ring',
                        text: 'không có biến nào khớp cấu hình',
                    });
                    return done();
                }

                msg.payload = lines.join('\n');
                msg.db = node.db;
                msg.precision = node.precision;

                node.status({
                    fill: 'green',
                    shape: 'dot',
                    text: `${lines.length} điểm dữ liệu`,
                });

                send(msg);
                done();
            } catch (err) {
                node.status({ fill: 'red', shape: 'ring', text: 'lỗi xử lý' });
                done(err as Error);
            }
        };

        // Ép kiểu khi đăng ký để tránh phụ thuộc overload không ổn định của
        // @types/node-red giữa các phiên bản (xem ghi chú DongtienInputListener).
        (node.on as (event: string, listener: DongtienInputListener) => Node).call(
            node,
            'input',
            onInput,
        );

        node.on('close', function () {
            node.status({});
        });
    }

    RED.nodes.registerType('dongtien-insert', DongtienInsertNode as never);
};

